// AUTO_DIFF CLASS FOR AUTOMATIC DIFFERENTIATION
template<typename T>
class AutoDiff {
public:
    T val; // value of the variable
    T der; // derivative of the variable

    AutoDiff(T val = 0.0, T der = 1.0) : val(val), der(der) {}

    // OPERATOR OVERLOADING FOR BASIC ARITHMETIC OPERATIONS
    AutoDiff operator+(const AutoDiff& other) const {
        return AutoDiff(val + other.val, der + other.der);
    }

    AutoDiff operator-(const AutoDiff& other) const {
        return AutoDiff(val - other.val, der - other.der);
    }

    AutoDiff operator*(const AutoDiff& other) const {
        return AutoDiff(val * other.val, val * other.der + der * other.val);
    }

    AutoDiff operator/(const AutoDiff& other) const {
        return AutoDiff(val / other.val, (val * other.der - der * other.val) / (other.val * other.val));
    }

    // OPERATOR OVERLOADING FOR UNARY OPERATIONS
    AutoDiff sin() const {
        return AutoDiff(std::sin(val), std::cos(val) * der);
    }

    AutoDiff cos() const {
        return AutoDiff(std::cos(val), -std::sin(val) * der);
    }

